    conn.execute(sa.text(
        "UPDATE reading_texts SET "
        "title_he = :th, content_he = :ch, "
        "content_ru = :cr, vocabulary_json = CAST(:vj AS jsonb) "
        "WHERE id = :tid"
    ), {
        "th": 'מילון סלנג: שורשים ושימושים',
        "ch": 'הסלנג הישראלי הוא תופעה לשונית דינמית המשתנה בקצב מסחרר. כל דור מביא איתו מילים חדשות, וחלקן נטמעות בשפה הסטנדרטית בעוד אחרות נעלמות תוך שנים ספורות. להלן מספר ערכים לדוגמה.\n\n"חבל על הזמן" — ביטוי שמשמעותו "מצוין" או "נהדר". האטימולוגיה שנויה במחלוקת: יש הטוענים שמקורו בערבית הדבורה, ויש הרואים בו קיצור של "חבל על הזמן שבזבזתי עד שגיליתי את זה". בשימוש מאז שנות השמונים.\n\n"פראייר" — מי שמאפשרים לנצל אותו; תמים, מטופש. מקור המילה ביידיש-גרמנית, מהמילה Freier (גבר חופשי, לקוח של זונה). בישראל עברה הסטה סמנטית: הפראייר הוא מי שמקפיד על חוקים כשאחרים לא. הביטוי "לא להיות פראייר" הוא כמעט ערך תרבותי.\n\n"יאללה" — מילת זירוז ממקור ערבי (يا الله, "הו אלוהים"). בעברית משמשת כ"בוא", "קדימה", "מהר". חדרה לשימוש כלל-ישראלי, ללא הבדל מגזרי. דוגמה לשאילה לשונית שהתנתקה לחלוטין ממשמעותה הדתית המקורית.\n\n"אחי" — כינוי חיבה בין גברים, מילולית "אחי". מקביל ל-bro באנגלית. שימוש רווח בקרב צעירים מכל המגזרים. הגרסה הנשית "אחותי" קיימת אך פחות נפוצה, ממצא המעורר שאלות מגדריות מעניינות.',
        "cr": 'Израильский сленг — динамическое языковое явление, меняющееся с головокружительной скоростью. Каждое поколение приносит новые слова, часть которых усваивается стандартным языком, а другие исчезают за считанные годы. Ниже несколько примеров словарных статей.\n\n«Хаваль аль hа-зман» — выражение, означающее «отлично» или «потрясающе». Этимология спорна: одни утверждают, что источник в разговорном арабском, другие видят сокращение фразы «жаль времени, что потратил, пока не обнаружил это». В употреблении с восьмидесятых годов.\n\n«Фраер» — тот, кем позволяют себя использовать; наивный, глупый. Происхождение — идиш-немецкое, от Freier (свободный мужчина, клиент проститутки). В Израиле произошёл семантический сдвиг: фраер — тот, кто соблюдает правила, когда другие этого не делают. Выражение «не быть фраером» — почти культурная ценность.\n\n«Яалла» — слово-побуждение арабского происхождения (يا الله, «о Боже»). В иврите используется как «давай», «вперёд», «быстрее». Вошло во всеизраильское употребление без секторальных различий. Пример языкового заимствования, полностью оторвавшегося от первоначального религиозного значения.\n\n«Ахи» — обращение между мужчинами, буквально «брат мой». Аналог английского bro. Широко распространено среди молодёжи всех секторов. Женский вариант «ахоти» существует, но менее распространён — факт, вызывающий интересные гендерные вопросы.',
        "vj": '[{"he": "סלנג", "ru": "сленг", "translit": "слэнг"}, {"he": "אטימולוגיה", "ru": "этимология", "translit": "этимолОгия"}, {"he": "הסטה סמנטית", "ru": "семантический сдвиг", "translit": "hасатА семАнтит"}, {"he": "שאילה לשונית", "ru": "языковое заимствование", "translit": "шеилА лешонИт"}, {"he": "פראייר", "ru": "фраер / простофиля", "translit": "фрайЕр"}, {"he": "מגזרי", "ru": "секторальный", "translit": "мигзарИ"}, {"he": "כינוי חיבה", "ru": "ласковое обращение", "translit": "кинУй хибА"}, {"he": "דינמי", "ru": "динамический", "translit": "динАми"}]',
        "tid": 198,
    })

